import json
import requests

IRIS_BASE_URL = "https://3.24.63.18"
IRIS_API_KEY = "iDZH2HAAV7pFtRtLZAo56oAxIs4CaFr8Lx9e_ZJeLsjp-UV654VGnOwryJCgr1ufWFGfjtrywaDciye043MBtw"

ctx = json.loads(r'''$build_soc_context''')["message"]
case_id = json.loads(r'''$create_new_iris_case''')["body"]["data"]["case_id"]

headers = {
    "Content-Type": "application/json",
    "Authorization": f"Bearer {IRIS_API_KEY}"
}

TYPE_MAP = {
    "ip": "79",
    "hostname": "69",
    "hash": "113",
    "domain": "20",
    "url": "141",
    "file": "37",
    "process": "107"
}

results = []

for obs in ctx.get("observables", []):
    obs_type = obs.get("type")
    value = obs.get("value")

    if not value:
        continue

    if obs_type not in TYPE_MAP:
        results.append({
            "value": value,
            "type": obs_type,
            "status": "skipped",
            "reason": "unsupported_type"
        })
        continue

    payload = {
        "cid": case_id,
        "ioc_type_id": TYPE_MAP[obs_type],
        "ioc_tlp_id": "2",
        "ioc_value": value,
        "ioc_tags": ",".join(obs.get("tags", [])),
        "ioc_description": f"{obs_type} extracted from Wazuh alert",
        "custom_attributes": {}
    }

    try:
        r = requests.post(
            f"{IRIS_BASE_URL}/case/ioc/add",
            headers=headers,
            json=payload,
            verify=False,
            timeout=10
        )

        try:
            response_body = r.json()
        except Exception:
            response_body = r.text

        results.append({
            "value": value,
            "type": obs_type,
            "status_code": r.status_code,
            "success": r.status_code == 200,
            "response": response_body
        })

    except Exception as e:
        results.append({
            "value": value,
            "type": obs_type,
            "success": False,
            "error": str(e)
        })

print(json.dumps({
    "case_id": case_id,
    "total_observables": len(ctx.get("observables", [])),
    "processed": len(results),
    "results": results
}))

